SELECT COUNT(DISTINCT LPB.PK) AS TOTAL FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB LPB ON LPB.PK = LPP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE S.GENERO = 'FEMININO' AND S.SIGLA_CAMPUS = 'OES' AND (LOWER(S.AREA_INGRESSO) LIKE LOWER('%farmacia%') OR LOWER(S.AREA_INGRESSO) LIKE LOWER('%farmacia%')) AND LOWER(LPB.TIPO) LIKE LOWER('%resumo de trabalhos%') AND LPB.ANO GLOB '[0-9][0-9][0-9][0-9]' AND CAST(LPB.ANO AS INTEGER) = 2024